const AWS = require('aws-sdk');
const { exec } = require('child_process');
const s3 = new AWS.S3();

exports.handler = async (event) => {
    try {
        const record = event.Records[0];
        const bucket = record.s3.bucket.name;
        const key = decodeURIComponent(record.s3.object.key.replace(/\+/g, ' '));
        const outputFormat = record.s3.object.metadata.outputFormat;

        const inputFilePath = `/tmp/${key}`;
        const outputFilePath = `/tmp/${key.split('.').slice(0, -1).join('.')}.${outputFormat}`;

        await downloadImage(bucket, key, inputFilePath);
        await convertImage(inputFilePath, outputFilePath);
        await uploadImage(bucket, outputFilePath, key.split('.').slice(0, -1).join('.') + `.${outputFormat}`);

        return { status: 'Image converted successfully' };
    } catch (error) {
        console.error(error);
        throw new Error('Image conversion failed');
    }
};

const downloadImage = (bucket, key, outputPath) => {
    return new Promise((resolve, reject) => {
        const params = { Bucket: bucket, Key: key };
        const file = require('fs').createWriteStream(outputPath);
        s3.getObject(params).createReadStream().pipe(file)
            .on('finish', resolve)
            .on('error', reject);
    });
};

const convertImage = (inputPath, outputPath) => {
    return new Promise((resolve, reject) => {
        const command = `convert ${inputPath} ${outputPath}`;
        exec(command, (error) => {
            if (error) {
                return reject(error);
            }
            resolve();
        });
    });
};

const uploadImage = (bucket, filePath, key) => {
    return new Promise((resolve, reject) => {
        const fileContent = require('fs').createReadStream(filePath);
        const params = { Bucket: bucket, Key: key, Body: fileContent };
        s3.upload(params, (error) => {
            if (error) {
                return reject(error);
            }
            resolve();
        });
    });
};